1	type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  (x !== otherX || y !== otherY) &&
5	  Math.abs(otherX - x) <= 1 &&
6	  Math.abs(otherY - y) <= 1;
7	
8	const countLiveNeighbors = (cell: Cell, livingCells: Cell[]): number =>
9	  livingCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const survives = (neighborCount: number): boolean =>
12	  neighborCount === 2 || neighborCount === 3;
13	
14	const reproduces = (neighborCount: number): boolean => neighborCount === 3;
15	
16	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
17	
18	const OFFSETS = [-1, 0, 1] as const;
19	
20	const neighborsOf = ([x, y]: Cell): Cell[] =>
21	  OFFSETS.flatMap((dx) =>
22	    OFFSETS
23	      .filter((dy) => dx !== 0 || dy !== 0)
24	      .map((dy): Cell => [x + dx, y + dy]),
25	  );
26	
27	const uniqueDeadNeighbors = (livingCells: Cell[]): Cell[] => {
28	  const liveKeys = new Set(livingCells.map(cellKey));
29	  const deadNeighbors = new Map<string, Cell>();
30	  for (const cell of livingCells) {
31	    for (const neighbor of neighborsOf(cell)) {
32	      const key = cellKey(neighbor);
33	      if (!liveKeys.has(key)) deadNeighbors.set(key, neighbor);
34	    }
35	  }
36	  return [...deadNeighbors.values()];
37	};
38	
39	export function nextGeneration(cells: Cell[]): Cell[] {
40	  const survivors = cells.filter((cell) =>
41	    survives(countLiveNeighbors(cell, cells)),
42	  );
43	  const births = uniqueDeadNeighbors(cells).filter((cell) =>
44	    reproduces(countLiveNeighbors(cell, cells)),
45	  );
46	  return [...survivors, ...births];
47	}
